INSERT INTO public.feltrip_local_picks (name, category, subcategory, city, neighborhood, description, description_en, website, highlights, is_active) VALUES
('Colégio Oswald de Andrade', 'school', 'progressive', 'São Paulo', 'Vila Madalena', 'Escola de elite intelectual focada em artes, pensamento crítico e formação humanista. Referência em pedagogia progressista.', 'Intellectual elite school focused on arts, critical thinking and humanist education. Reference in progressive pedagogy.', 'https://colegiooswald.com.br', ARRAY['Artes', 'Pensamento Crítico', 'Progressista'], true),
('Graded School', 'school', 'international', 'São Paulo', 'Morumbi', 'A mais tradicional escola americana de São Paulo. Currículo americano completo com diploma reconhecido nos EUA.', 'The most traditional American school in São Paulo. Complete American curriculum with US-recognized diploma.', 'https://www.graded.br', ARRAY['Americana', 'Internacional', 'Bilíngue'], true),
('St. Paul''s School', 'school', 'international', 'São Paulo', 'Jardins', 'O padrão britânico em São Paulo. Currículo britânico com exames IGCSE e A-Levels.', 'The British standard in São Paulo. British curriculum with IGCSE and A-Level exams.', 'https://www.stpauls.br', ARRAY['Britânica', 'Internacional', 'Bilíngue'], true),
('Colégio Equipe', 'school', 'humanist', 'São Paulo', 'Higienópolis', 'Excelente base humanista com valores mais acessíveis. Formação crítica e cidadã.', 'Excellent humanist foundation with more accessible fees. Critical and civic education.', 'https://colegioequipe.g12.br', ARRAY['Humanista', 'Acessível', 'Pensamento Crítico'], true),
('Colégio Santa Cruz', 'school', 'humanist', 'São Paulo', 'Alto de Pinheiros', 'Humanista e construtivista. Uma das mais desejadas pela elite intelectual. Foco na formação do cidadão pensante.', 'Humanist and constructivist. One of the most desired by the intellectual elite. Focus on forming thinking citizens.', 'https://santacruz.g12.br', ARRAY['Humanista', 'Construtivista', 'Elite Intelectual'], true),
('Colégio Bandeirantes', 'school', 'traditional', 'São Paulo', 'Vila Mariana', 'Alta Performance Acadêmica. Foco rigoroso em exatas e vestibulares de medicina/engenharia. Muito competitivo.', 'High Academic Performance. Rigorous focus on exact sciences and medical/engineering entrance exams. Very competitive.', 'https://colband.com.br', ARRAY['Alta Performance', 'Exatas', 'Competitivo'], true),
('Colégio Dante Alighieri', 'school', 'traditional', 'São Paulo', 'Jardins', 'Tradicional e histórica com raízes italianas. Infraestrutura gigantesca e forte investimento em laboratórios e ciências.', 'Traditional and historic with Italian roots. Massive infrastructure and strong investment in labs and sciences.', 'https://dante.org.br', ARRAY['Tradicional', 'Italiano', 'Ciências'], true),
('Colégio Rio Branco', 'school', 'traditional', 'São Paulo', 'Higienópolis', 'Tradicional, mas com olhar para inovação. Localização privilegiada e foco em formação integral.', 'Traditional but innovation-minded. Prime location and focus on integral education.', 'https://crb.g12.br', ARRAY['Tradicional', 'Inovação', 'Formação Integral'], true),
('Avenues São Paulo', 'school', 'international', 'São Paulo', 'Cidade Jardim', 'A "Escola Global". Tecnologia de ponta, imersão total em inglês e foco em currículo internacional. Mensalidades no topo da pirâmide.', 'The "Global School". Cutting-edge technology, full English immersion and international curriculum focus. Top-tier tuition.', 'https://avenues.org/sp', ARRAY['Global', 'Internacional', 'Premium'], true),
('Red House International School', 'school', 'international', 'São Paulo', 'Morumbi', 'Escola bilíngue internacional da Educação Infantil ao Ensino Médio. Excelência acadêmica e formação global.', 'International bilingual school from Early Childhood to High School. Academic excellence and global education.', 'https://redhouse.com.br', ARRAY['Internacional', 'Bilíngue', 'Global'], true),
('ETECs - Escolas Técnicas Estaduais', 'school', 'public', 'São Paulo', 'Diversos', 'Escolas públicas que unem Ensino Médio ao técnico. Muitas figuram entre as 10 melhores notas do ENEM. Entrada via Vestibulinho.', 'Public schools combining High School with technical education. Many rank among the top 10 ENEM scores. Entry via entrance exam.', 'https://vestibulinhoetec.com.br', ARRAY['Técnica', 'Gratuita', 'Alta Performance'], true),
('Escola de Aplicação da USP', 'school', 'public', 'São Paulo', 'Butantã', 'Escola-laboratório dentro da USP onde professores testam métodos pedagógicos. Ensino crítico e criativo de altíssima qualidade. Entrada por sorteio.', 'Laboratory school within USP where professors test pedagogical methods. Critical and creative teaching of highest quality. Entry by lottery.', 'https://escolaaplicacao.usp.br', ARRAY['USP', 'Gratuita', 'Elite Acadêmica'], true),
('Colégio Termomecânica', 'school', 'public', 'São Paulo', 'São Bernardo do Campo', 'Escola filantrópica 100% gratuita com qualidade nível Avenues/Bandeirantes. Entrada via prova de seleção.', 'Philanthropic school, 100% free with Avenues/Bandeirantes level quality. Entry via selection test.', 'https://colegio.termomecanica.com.br', ARRAY['Filantrópica', 'Gratuita', 'Elite Acadêmica'], true),
('CEUs - Centros Educacionais Unificados', 'school', 'public', 'São Paulo', 'Diversos', 'Complexos municipais que unem escola, piscina, teatro e biblioteca. Coração cultural de bairros periféricos.', 'Municipal complexes combining school, pool, theater and library. Cultural heart of peripheral neighborhoods.', 'https://educacao.sme.prefeitura.sp.gov.br', ARRAY['Municipal', 'Gratuita', 'Infraestrutura'], true),
('PEI - Escolas de Ensino Integral', 'school', 'public', 'São Paulo', 'Diversos', 'Escolas estaduais em tempo integral (7h às 16h/19h). Currículo moderno com foco em Projeto de Vida.', 'Full-time state schools (7am to 4pm/7pm). Modern curriculum focused on Life Project.', 'https://sed.educacao.sp.gov.br', ARRAY['Estadual', 'Gratuita', 'Tempo Integral'], true);